correct_answer:
s = 'HeLLo WoRLD'
result = ''
for char in s:
    if char.islower():
        result += char.upper()
    elif char.isupper():
        result += char.lower()
    else:
        result += char
print(result)

example:
# Example: swap case of 'Hi'
s = 'Hi'
result = ''
for char in s:
    if char.islower():
        result += char.upper()
    elif char.isupper():
        result += char.lower()
    else:
        result += char
print(result)

# Example: leap years from 2000 to 2020
for year in range(2000, 2021):
    if (year % 4 == 0 and year % 100 != 0) or (year % 400 == 0):
        print(year)

